SELECT SUM(total_size) AS total_coflow_size
FROM coflows
WHERE priority = 'high';

SELECT AVG(CAST(REPLACE(value, '%', '') AS REAL)) AS average_packet_loss_rate
FROM flow_metrics
WHERE metric_type = 'packet loss rate';

SELECT MAX(value) AS max_throughput
FROM flow_metrics
WHERE metric_type = 'throughput';

SELECT AVG(CAST(value AS REAL) / 1048576) AS average_flow_size_in_mb
FROM coflow_metrics
WHERE metric_type = 'average flow size';

SELECT total_size 
FROM coflows 
WHERE priority = 'high';

SELECT metric_type
FROM device_metrics
WHERE CAST(REPLACE(value, '%', '') AS REAL) = (
    SELECT MAX(CAST(REPLACE(value, '%', '') AS REAL))
    FROM device_metrics
);
